/**
 * Render inline SVG icon.
 *
 * @param string $name  Icon name.
 * @param string $class Extra classes.
 */
function ac_tech_icon( $name, $class = '' ) {
	$icons = ac_tech_get_icon_svgs();
	$path  = isset( $icons[ $name ] ) ? $icons[ $name ] : '';

	if ( '' === $path ) {
		return;
	}

	$classes = trim( 'ac-tech-icon ' . $class );

	printf(
		'<svg class="%s" width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" focusable="false">%s</svg>',
		esc_attr( $classes ),
		$path // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- static SVG paths.
	);
}
